/* Watchman Forge — GTR burnout hero. Renders into <canvas id="hero-canvas">. */
(function(){
  var canvas = document.getElementById('hero-canvas');
  if(!canvas) return;
  var CW=1536, CH=1024;
  canvas.width=CW; canvas.height=CH;
  var ctx = canvas.getContext('2d');
  var FRONT={x:332,y:597}, REAR={x:1234,y:584}, D=194, capD=34;
  var base=new Image(), wheel=new Image(), cap=new Image(), fender=new Image();
  var n=4, ready=false; function rdy(){ if(--n===0){ ready=true; document.documentElement.classList.add('hero-ready'); init(); } }
  base.onload=rdy; wheel.onload=rdy; cap.onload=rdy; fender.onload=rdy;
  base.src="data:image/jpeg;base64,"; wheel.src="data:image/png;base64,";
  cap.src="data:image/png;base64,"; fender.src="data:image/png;base64,";

  var reduce = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  function sprite(s,st){var c=document.createElement('canvas');c.width=c.height=s;var g=c.getContext('2d');
    var rg=g.createRadialGradient(s/2,s/2,0,s/2,s/2,s/2);for(var i=0;i<st.length;i++)rg.addColorStop(st[i][0],st[i][1]);
    g.fillStyle=rg;g.fillRect(0,0,s,s);return c;}
  var smokeS,glowC,glowB,t=0,angle=0,parts=[],SPIN=13,BLURN=7,SPREAD=20,raf=null,visible=true;
  function rnd(a,b){return a+Math.random()*(b-a);}
  function init(){
    smokeS=sprite(128,[[0,'rgba(212,218,230,1)'],[0.5,'rgba(205,212,226,0.5)'],[1,'rgba(205,212,226,0)']]);
    glowC=sprite(360,[[0,'rgba(95,234,255,1)'],[0.35,'rgba(60,165,255,0.55)'],[1,'rgba(60,165,255,0)']]);
    glowB=sprite(360,[[0,'rgba(55,115,255,1)'],[1,'rgba(55,115,255,0)']]);
    if(reduce){ drawStatic(); return; }
    start();
  }
  function start(){ if(!raf && ready && !reduce) raf=requestAnimationFrame(frame); }
  function stop(){ if(raf){ cancelAnimationFrame(raf); raf=null; } }
  function drawStatic(){
    ctx.clearRect(0,0,CW,CH); ctx.drawImage(base,0,0,CW,CH);
    [FRONT,REAR].forEach(function(w){ ctx.save();ctx.translate(w.x,w.y);ctx.drawImage(wheel,-D/2,-D/2,D,D);ctx.restore(); });
    ctx.drawImage(cap,FRONT.x-capD/2,FRONT.y-capD/2,capD,capD);
    ctx.drawImage(cap,REAR.x-capD/2,REAR.y-capD/2,capD,capD);
    ctx.drawImage(fender,0,0,CW,CH);
  }
  function drawWheel(w){ for(var i=0;i<BLURN;i++){ var a=(angle+(i/(BLURN-1)-0.5)*SPREAD)*Math.PI/180;
    ctx.save();ctx.globalAlpha=1/BLURN;ctx.translate(w.x,w.y);ctx.rotate(a);ctx.drawImage(wheel,-D/2,-D/2,D,D);ctx.restore();} ctx.globalAlpha=1; }
  function drawCap(w,ph){ var wob=Math.sin(t*0.05+ph)*0.07; var fy=Math.sin(t*0.04+ph)*0.7;
    ctx.save();ctx.translate(w.x,w.y+fy);ctx.rotate(wob);ctx.drawImage(cap,-capD/2,-capD/2,capD,capD);ctx.restore(); }
  function underglow(){ ctx.save();ctx.globalCompositeOperation='lighter';
    var pulse=0.6+0.18*Math.sin(t*0.05),xs=[420,700,980,1235];
    for(var j=0;j<xs.length;j++){var s=440*pulse;ctx.globalAlpha=0.22*pulse;ctx.drawImage(glowB,xs[j]-s/2,700-s/2,s,s);}
    var per=260,pp=(t%per)/per;
    for(var k=0;k<6;k++){var q=pp-k*0.035;if(q<0||q>1)continue;
      var xx=1240+(330-1240)*q,yy=694-Math.sin(q*Math.PI)*6,ff=Math.sin(q*Math.PI),s2=330*(1-k*0.07);
      ctx.globalAlpha=0.46*ff*(1-k/6.5);ctx.drawImage(glowC,xx-s2/2,yy-s2/2,s2,s2);}
    ctx.restore();ctx.globalAlpha=1; }
  function smoke(){
    if(t%2===0)parts.push({x:REAR.x+rnd(-12,30),y:688,vx:rnd(0.5,1.9),vy:-rnd(0.4,1.2),r:rnd(16,30),a:0.15+rnd(0,0.05)});
    if(t%4===0)parts.push({x:FRONT.x+rnd(-8,22),y:700,vx:rnd(0.4,1.5),vy:-rnd(0.4,1.0),r:rnd(14,26),a:0.10+rnd(0,0.04)});
    if(parts.length>95)parts.splice(0,parts.length-95);
    ctx.save();
    for(var i=parts.length-1;i>=0;i--){var q=parts[i];q.x+=q.vx;q.y+=q.vy;q.vy-=0.004;q.vx*=0.996;q.r+=0.7;q.a*=0.984;
      if(q.a<0.006){parts.splice(i,1);continue;}ctx.globalAlpha=q.a;ctx.drawImage(smokeS,q.x-q.r,q.y-q.r,q.r*2,q.r*2);}
    ctx.restore();ctx.globalAlpha=1; }
  function frame(){ t++;angle+=SPIN;ctx.clearRect(0,0,CW,CH);ctx.drawImage(base,0,0,CW,CH);
    underglow();drawWheel(FRONT);drawWheel(REAR);drawCap(FRONT,0);drawCap(REAR,1.4);
    ctx.drawImage(fender,0,0,CW,CH);smoke();raf=requestAnimationFrame(frame); }

  function resume(){ if(!ready) return; if(reduce) drawStatic(); else start(); }
  if('IntersectionObserver' in window){
    var io=new IntersectionObserver(function(es){ es.forEach(function(e){
      visible=e.isIntersecting; if(!ready) return; if(visible) resume(); else if(!reduce) stop(); }); },{threshold:0.01});
    io.observe(canvas);
  }
  document.addEventListener('visibilitychange',function(){ if(document.hidden) stop(); else if(visible) resume(); });
  // Mobile resilience: the address bar hiding/showing on scroll fires a viewport resize, and iOS
  // can purge an off-screen canvas's backing store — repaint so the car never vanishes on scroll.
  var rt; function onViewport(){ clearTimeout(rt); rt=setTimeout(function(){ if(visible) resume(); }, 60); }
  window.addEventListener('resize', onViewport, {passive:true});
  window.addEventListener('orientationchange', function(){ setTimeout(function(){ if(visible) resume(); }, 200); }, {passive:true});
  window.addEventListener('pageshow', function(){ if(visible) resume(); }, {passive:true});
  if(window.visualViewport){ window.visualViewport.addEventListener('resize', onViewport, {passive:true}); }
  if(reduce){ var st; window.addEventListener('scroll', function(){ if(st) return; st=setTimeout(function(){ st=null; if(visible) drawStatic(); }, 150); }, {passive:true}); }
})();
